import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a1 as a,a2 as m,a0 as d,C as o}from"./framework-91490e6a.js";const b={},f=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),g={href:"https://tree-novel.com/works/episode/9a6655bb83bbfec637a36295b1c318a0.html",target:"_blank",rel:"noopener noreferrer"},h=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>身体不舒服。</p><p>再次独自一人旅行了大约一周，那种疲劳感涌上心头，即使过了几天，我仍然经常感到困倦和疲劳。看来愉快和疲劳是等价的。不过，善良的读者朋友们不用担心我。因为这个专栏连载离刊登有几周的滞后，所以在你们阅读的这一刻，我已经在为其他事情而烦恼了。</p><p>那么，这时候我真的感到孤独和渴望有人陪伴。然而，因为从未有过向别人求助「身体不舒服，帮帮我～」的经验，所以不知道该怎么办。</p><p>倒不如说，从逻辑上来讲，在身体不适的情况下，特意向朋友寻求帮助似乎没有意义。如果情况非常糟糕，痛苦到不能动弹，可以叫救护车；即使可能会懒得动，但如果你还能行动，就可以自己去医院或买药。总之，睡眠是最简单的康复方式，所以无论如何只需睡眠就好。虽然在身体虚弱时有朋友在身边可能会让人感到安心，但那只是精神层面的事情，从基本上说，一切都可以自己解决。</p><p>考虑到这些，最终我选择独自面对。而且，我甚至认为自己能够独力解决问题很「酷」。我沉迷于孤独中。然而，现在我应该要从这种耍酷的方式中毕业了。</p><p>一位与我一起制作游戏的制作人也对我说：「也许你应该练习与人相处。」</p><p>我的脑海中像是通了电一般。当我谈到「我又一个人出去旅行了哦～果然还是一个人旅行更加合适」的时候，他的反应是：「即使那样对你来说更开心，也可以和别人分享分享活动的经验嘛」。说得对，无论是否独自旅行更加愉快，更重要的还是积累与他人一起协调行程和目标的经验。一时的快乐并不是时间的唯一价值。我们应该去「挑战」「共同体验事物」的机会。</p><p>这是一个我之前没有考虑到的盲点。所以，在这种情况下，作为一种体验，我应该向朋友和熟人发出SOS信号：「最近身体不太好啊～」</p><p>……但，我还是没有采取任何行动。尽管这样，我仍然觉得「叫来有什么用？」而且我有足够的时间去便利店或药店。不过，明明都说了不应该这样的……</p><p>嘛，这次就这样吧。就像开头所说的，我想下个月我就会为完全不同的问题而烦恼。也许与长期疲劳感一起。不管怎样，至少我可以先提交这篇专栏，然后好好休息。</p><p>晚安。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/857e71e959cb41df5f7d36ca11402a9a.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/c3c1db2dacdbfd5674de94192818dcdb.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/875b523cfab0d4ce2bca972ab01be551.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【房间的墙】我试着在我的卧室墙上装饰上画作和蝴蝶标本，效果非常棒。感觉就像一个艺术馆一样。如果我去世了，希望有人可以将我的房间作为旅游景点开放。请多关照。</p></blockquote>',15);function u(y,x){const l=o("ExternalLinkIcon"),n=o("RouterLink");return s(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",g,[t("第24回／咳をしても一人"),a(l)])]),e("blockquote",null,[h,e("p",null,[a(n,{to:"/posts/Translate/nyalra_kb_23.html"},{default:m(()=>[t("【奈亚拉面壁自语】第23回｜每日牺牲一小时的觉悟【230425】")]),_:1})])]),k])}const V=c(b,[["render",u],["__file","nyalra_kb_24.html.vue"]]);export{V as default};
